#include <bits/stdc++.h>
using namespace std;

int main(){
    int n,a;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>a;
        if (a<3){
            cout<<1<<endl;
        }else{
            int b=1,c=1,d;
            for(int u=0;u<a-2;u=u+1){
                d=b+c;
                b=c;
                c=d;
            }
            cout<<d<<endl;
        }
    }
    return 0;
}
